-    exit(EXIT_FAILURE);
-  }
-  // load vocab_size, bos_tok, eos_tok
-  vocab_size_ = _processor->GetPieceSize();
-  bos_tok_ = _processor->bos_id();
-  eos_tok_ = _processor->eos_id();
-  initialized_ = true;
