- */
-std::string SPTokenizer::decode(uint64_t prev_token, uint64_t token) {
-  if (!initialized_) {
-    fprintf(stderr, "Tokenizer not initialized\n");
-    exit(EXIT_FAILURE);
-  }
-  // get rid of the control ids <s> and </s>
-  if (_processor->IsControl(token)) {
